    <div id="branches-data" style="display:none;">$1</div>
    <div class="dreamcore-container">
        <div class="branch-card" id="branchCard">
            <div class="branch-header" onclick="toggleBranch()">
                <span class="header-title">
                    <span class="header-icon">✦</span>
                    <span>梦 境 分 支</span>
                    <span class="header-icon">✦</span>
